  ('aboriginal-7c9828ae-moex-00056', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '有關司法院院長之職權及地位，下列敘述何者錯誤？', '["綜理院務，監督所屬機關", "並為大法官之院長不受任期保障", "依據憲法第44條規定，出席總統主持之院際調解", "提請總統任命司法院副院長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00057', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '依司法院大法官解釋，土地稅法規定，依都市計畫法指定之公共設施保留地，免徵土地增值稅；至非都市 土地經編定為交通用地，且依法核定為公共設施用地者，則不予免徵土地增值稅之規定，係違反下列何種 基本權？', '["生存權", "財產權", "工作權", "平等權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00058', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '關於地方自治之敘述，下列何者錯誤？', '["屬於垂直權力分立（中央、省、縣）之設計", "地方自治為地方人民自我決定地方事務之表現", "地方自治的存在僅限於行政上的分治，而無政治上的分權", "地方自治團體為公法人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00059', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '原住民族文化資產之指定或登錄，除依各類別審議基準外，下列何者非屬應符合之條件？', '["表現原住民族土地的重要關聯性", "表現原住民族世代相傳之傳承性", "表現原住民族文化之歷史重要性或具代表性", "表現特定原住民族、部落或其他傳統組織之文化顯著性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00060', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '申請無償取得原住民保留地所有權，有若干資格上之限制。下列敘述何者正確？', '["原住民依法於原住民保留地設定農育權者", "原住民依法於原住民保留地取得抵押權者", "原住民提出申請後經由部落會議同意取得者", "經原住民保留地土地權利審查委員會同意者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00061', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '為保障原住民族工作權，中央主管機關依法應於原住民族綜合發展基金項下設置就業基金。下列關於該基 金之敘述，何者正確？', '["其收支、保管及運用辦法，依法由原住民族委員會定之", "其收支、保管及運用辦法，由行政院授權地方政府定之", "就業基金之來源，包含依原住民族工作權保障法所繳納之代金", "就業基金之來源，限於依原住民族工作權保障法所繳納之代金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00062', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '根據原住民族工作權保障法，依政府採購法得標之廠商，於國內員工總人數逾100人者，負有應僱用一定 比例原住民之要求。下列有關此規定之敘述，何者錯誤？', '["其僱用之人數不得低於總人數百分之一", "若僱用之人數未達標準，則須繳納代金", "應於履約期間符合僱用一定比例之義務", "於投標時即須符合僱用一定比例之義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00063', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '關於原住民族在經中央原住民族主管機關公告之海域採集野生植物及菌類之行為，下列敘述何者正確？', '["得依法從事非營利行為", "限於環境部公告之海域", "不以傳統文化、祭儀或自用為限", "須經中央原住民族主管機關同意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
